<?php // database.php $localConfig = __DIR__. '/database.local.php'; $httpHost = $_SERVER['HTTP_HOST']?? ($_SERVER['SERVER_NAME']?? ''); $isLocalHost = in_array($httpHost, ['127.0.0.1', 'localhost'], true); $isCli = (PHP_SAPI === 'cli'); if (($isLocalHost || $isCli) && file_exists($localConfig)) { require_once $localConfig; } $requiredKeys = ['DB_HOST', 'DB_NAME', 'DB_USER']; foreach ($requiredKeys as $key) { if (!defined($key)) { $envValue = getenv($key); if ($envValue!== false && $envValue!== '') { define($key, $envValue); } } } $missingKeys = []; foreach ($requiredKeys as $key) { if (!defined($key) || constant($key) === '') { $missingKeys[] = $key; } } if (!defined('DB_PASS')) { $envValue = getenv('DB_PASS'); if ($envValue!== false) { define('DB_PASS', $envValue); } else { define('DB_PASS', ''); } } if (!defined('DB_PORT')) { $envValue = getenv('DB_PORT'); if ($envValue!== false && $envValue!== '') { define('DB_PORT', $envValue); } else { define('DB_PORT', '3306'); } } if (!empty($missingKeys)) { throw new RuntimeException('Database configuration missing: '. implode(', ', $missingKeys)); } class Database { private $conn; public function __construct { $options = [ PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION, PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC, PDO::ATTR_EMULATE_PREPARES => false ]; $dsnWithDb = "mysql:host=". DB_HOST. ";port=". DB_PORT. ";dbname=". DB_NAME. ";charset=utf8mb4"; $dsnNoDb = "mysql:host=". DB_HOST. ";port=". DB_PORT. ";charset=utf8mb4"; try { $this->conn = new PDO($dsnWithDb, DB_USER, DB_PASS, $options); } catch (PDOException $e) { $message = $e->getMessage; if (stripos($message, 'Unknown database')!== false) { try { $bootstrap = new PDO($dsnNoDb, DB_USER, DB_PASS, $options); $dbName = str_replace('`', '``', DB_NAME); $bootstrap->exec("CREATE DATABASE IF NOT EXISTS `{$dbName}` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci"); $this->conn = new PDO($dsnWithDb, DB_USER, DB_PASS, $options); } catch (PDOException $inner) { die("Connection failed: ". $inner->getMessage); } } else { die("Connection failed: ". $message); } } } public function getConnection { return $this->conn; } }?>
